import defusedxml.ElementTree as ET
from typing import Dict, Any, Union


def parse_xml_config(xml_file_path: str) -> Dict[str, Any]:
    """
    Parse an XML configuration file and return settings as a dictionary.
    
    Args:
        xml_file_path: Path to the XML configuration file
        
    Returns:
        Dictionary containing the configuration settings
    """
    tree = ET.parse(xml_file_path)
    root = tree.getroot()
    
    def element_to_dict(element) -> Union[Dict[str, Any], str, None]:
        """
        Recursively convert XML element to dictionary.
        """
        result = {}
        
        # Add attributes if present
